62	/**@ch 懸賞令管理器*/
63	@ccclass('WantedPosterManager')
64	export class WantedPosterManager extends Component {
65	    //#region Constants
66	    /**
67	     * @ch 需要註冊的事件列表
68	     */
69	    private static readonly EVENTS_TO_REGISTER = [
70	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
72	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
74	        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	    //#endregion Constants
78	
79	    //#region Properties
80	    @property({
81	        type: Node,
82	        tooltip: "根節點"
83	    })
84	    private m_rootNode: Node = null;
85	
86	    @property({
87	        type: [WantedPosterItem],
88	        tooltip: "懸賞令物品"
89	    })
90	    private m_wantedPosterItems: WantedPosterItem[] = [];
91	
92	    @property({
93	        type: Layout,
94	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
95	    })
96	    private m_layout: Layout = null;
97	
98	    @property({
99	        type: WantedPosterLayoutConfig,
100	        tooltip: "直向排版設定"
101	    })
102	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "橫向排版設定"
107	    })
108	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 是否已初始化*/
113	    private m_isInitialized: boolean = false;
114	
115	    /**
116	     * @ch 各 item 目前綁定的懸賞令資料（null = 該 item 未顯示）
117	     * 與 m_wantedPosterItems 同索引，是「同 BaseSymbol 持續判斷」與「倍率是否變」的真實依據
118	     * （item 本身只記 BaseSymbol、不記 Multiple，故由 Manager 統一追蹤）
119	     */
120	    private m_currentBounty: (IBountyData | null)[] = [];
121	    //#endregion Variables
122	
123	    //#region Lifecycle
124	    /**@ch 元件載入時調用*/
125	    onLoad() {
126	        this.RegisterEvent();
127	        this.RegisterKeyboardEvents();
128	        this.EnsureCurrentBountySize();
129	    }
130	
131	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
132	    start() {
133	        this.ApplyLayoutByOrientation();
134	    }
135	
136	    /**@ch 元件銷毀時調用*/
137	    onDestroy() {
138	        if (!this.m_isInitialized) return;
139	        this.UnregisterEvent();
140	        this.UnregisterKeyboardEvents();
141	        this.m_isInitialized = false;
142	    }
143	    //#endregion Lifecycle
144	
145	    //#region Event Management
146	    /**@ch 註冊鍵盤事件（測試用）*/
147	    private RegisterKeyboardEvents(): void {
148	        if (!DEBUG) return;
149	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
150	    }
151	
152	    /**@ch 取消註冊鍵盤事件（測試用）*/
153	    private UnregisterKeyboardEvents(): void {
154	        if (!DEBUG) return;
155	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
156	    }
157	
158	    /**@ch 註冊事件*/
159	    private RegisterEvent() {
160	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
161	            eventManager.Register(eventName, this);
162	        });
163	        this.m_isInitialized = true;
164	    }
165	
166	    /**@ch 取消註冊事件*/
167	    private UnregisterEvent() {
168	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
169	            eventManager.UnRegister(eventName, this);
170	        });
171	    }
172	
173	    /**
174	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
175	     * @param args 事件參數
176	     * @returns 是否有效
177	     */
178	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
179	        if (typeof args[0] !== 'boolean') {
180	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
181	            return false;
182	        }
183	        return true;
184	    }
185	
186	    /**
187	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
188	     * @param args 事件參數
189	     * @returns 是否有效
190	     */
191	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
192	        if (!Array.isArray(args[0])) {
193	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
194	            return false;
195	        }
196	        return true;
197	    }
198	
199	    /**
200	     * @ch 事件回調
201	     * @param event 事件名稱
202	     * @param args 事件參數
203	     */
204	    OnEvent(event: string, ...args: any[]) {
205	        switch (event) {
206	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
207	                if (this.ValidateSetWantedPosterDataArgs(args)) {
208	                    this.SetWantedPosterData(
209	                        args[0] as IBountyData[],
210	                        args[1] === true,
211	                        Array.isArray(args[2]) ? args[2] as number[] : undefined
212	                    );
213	                }
214	                break;
215	
216	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
217	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
218	                    this.SetWantedPosterUIShow(args[0] as boolean);
219	                }
220	                break;
221	
222	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
223	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
224	                break;
225	
226	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
227	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
228	                break;
229	
230	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
231	                this.HandleGameIntroComplete();
232	                break;
233	
234	            case GAME_EVENT.DEVICE_ROTATION:
235	                this.ApplyLayoutByOrientation();
236	                break;
237	
238	            default:
239	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
240	        }
241	    }
242	
243	    /**
244	     * @ch 依目前裝置方向套用對應的 Layout 設定
245	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
246	     */
247	    private ApplyLayoutByOrientation(): void {
248	        if (!this.m_layout) {
249	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
250	            return;
251	        }
252	        const isLandscape = Common.GetGameView().IsLandscape;
253	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
254	
255	        this.m_layout.type = cfg.type;
256	        this.m_layout.resizeMode = cfg.resizeMode;
257	        this.m_layout.paddingLeft = cfg.paddingLeft;
258	        this.m_layout.paddingRight = cfg.paddingRight;
259	        this.m_layout.paddingTop = cfg.paddingTop;
260	        this.m_layout.paddingBottom = cfg.paddingBottom;
261	        this.m_layout.spacingX = cfg.spacingX;
262	        this.m_layout.spacingY = cfg.spacingY;
263	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
264	        this.m_layout.alignVertical = cfg.alignVertical;
265	        this.m_layout.updateLayout();
266	    }
267	
268	    /**
269	     * @ch 處理 PLAY_MARK 事件
270	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
271	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
272	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
273	     * EH-9：resolve callback 缺失 → error（caller bug）
274	     */
275	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
276	        if (typeof resolve !== 'function') {
277	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
278	            return;
279	        }
280	        const items = this.GetItemsByBaseSymbol(baseSymbol);
281	        if (items.length === 0) {
282	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
283	            resolve();
284	            return;
285	        }
286	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
287	    }
288	
289	    /**
290	     * @ch 處理 PLAY_MARK_ACTIVE 事件
291	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
292	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
293	     * EH-9：resolve callback 缺失 → error
294	     */
295	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
296	        if (typeof resolve !== 'function') {
297	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
298	            return;
299	        }
300	        const items = this.GetItemsByBaseSymbol(baseSymbol);
301	        if (items.length === 0) {
302	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
303	            resolve();
304	            return;
305	        }
306	        Promise.all(items.map(item =>
307	            item.PlayMarkActive().then(() => {
308	                item.node.active = false;
309	                // 收尾關閉 item → 同步清除綁定，避免與 m_currentBounty 失同步
310	                const idx = this.m_wantedPosterItems.indexOf(item);
311	                if (idx >= 0) this.m_currentBounty[idx] = null;
312	            })
313	        )).then(() => resolve());
314	    }
315	
316	    /**
317	     * @ch 處理 GAME_INTRO_COMPLETE 事件
318	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）為「已定位」靜止畫面（不播 In 進場）。
319	     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
320	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
321	     */
322	    private HandleGameIntroComplete() {
323	        this.EnsureCurrentBountySize();
324	        const item = this.m_wantedPosterItems[0];
325	        if (!item) {
326	            warn('[WantedPosterManager] GAME_INTRO_COMPLETE: 懸賞令物品[0] 未設置');
327	            return;
328	        }
329	        const data: IBountyData = { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 };
330	        // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
331	        item.node.active = true;
332	        item.SetWantedPosterData(data);
333	        item.ShowInSettled();           // 直接顯示 In 定位完成的靜止畫面（不播進場）
334	        this.m_currentBounty[0] = data;
335	    }
336	    //#endregion Event Management
337	
338	    //#region Methods
339	    /**
340	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
341	     *
342	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
343	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
344	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
345	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
346	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
347	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
348	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
349	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
350	     *
351	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
352	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
353	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
354	     */
355	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
356	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
357	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
358	            return;
359	        }
360	        this.EnsureCurrentBountySize();
361	
362	        const count = this.m_wantedPosterItems.length;
363	        // 本輪要顯示的 bounty（Multiple>0），超量截斷至 item 數量上限
364	        const newBounties = dataList.filter(d => d && d.Multiple > 0);
365	        if (newBounties.length > count) {
366	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
367	                newBounties.length, '>', count);
368	            newBounties.length = count;
369	        }
370	
371	        if (isNewRound) {
372	            this.RebuildAll(newBounties);
373	        } else {
374	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
375	        }
376	    }
377	
378	    /**
379	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
380	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
381	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
382	     */
383	    private RebuildAll(newBounties: IBountyData[]) {
384	        const count = this.m_wantedPosterItems.length;
385	
386	        const outPromises: Promise<void>[] = [];
387	        for (let i = 0; i < count; i++) {
388	            const item = this.m_wantedPosterItems[i];
389	            if (item && item.node.active) {
390	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
391	            }
392	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
393	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
394	        }
395	
396	        const enterAll = () => {
397	            for (let i = 0; i < newBounties.length; i++) {
398	                const item = this.m_wantedPosterItems[i];
399	                if (!item) continue;
400	                // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
401	                item.node.active = true;
402	                item.SetWantedPosterData(newBounties[i]);
403	                item.PlayIn();
404	            }
405	        };
406	
407	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
408	        else enterAll();
409	    }
410	
411	    /**
412	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
413	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
414	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
415	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
416	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
417	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
418	     */
419	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
420	        const count = this.m_wantedPosterItems.length;
421	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
422	
423	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
424	        const pool = new Map<number, IBountyData[]>();
425	        for (const b of newBounties) {
426	            const list = pool.get(b.BaseSymbol);
427	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
428	        }
429	
430	        const preFreeSlots: number[] = [];      // 更新前就空著的 item，供進場立即使用
431	        const vacatingSlots: number[] = [];     // 本輪退場騰出的 item，Out 完才可用
432	        const outPromises: Promise<void>[] = [];
433	        const deferredEnter: IBountyData[] = [];
434	
435	        // Pass A：逐一決定目前已綁定 item 的命運
436	        for (let i = 0; i < count; i++) {
437	            const cur = this.m_currentBounty[i];
438	            const item = this.m_wantedPosterItems[i];
439	            if (cur === null) {
440	                if (item) preFreeSlots.push(i);
441	                continue;
442	            }
443	            const bs = cur.BaseSymbol;
444	            const list = pool.get(bs);
445	            if (list && list.length > 0) {
446	                const onBoard = visible ? visible.has(bs) : true;
447	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
448	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
449	                if (sameIdx >= 0) {
450	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
451	                } else {
452	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場
453	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
454	                    this.m_currentBounty[i] = nb;
455	                }
456	                if (list.length === 0) pool.delete(bs);
457	            } else {
458	                // BC-22 新清單已無此 BaseSymbol → 退場
459	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
460	                this.m_currentBounty[i] = null;
461	                vacatingSlots.push(i);
462	            }
463	        }
464	
465	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
466	        const remaining: IBountyData[] = [];
467	        for (const list of pool.values()) remaining.push(...list);
468	        for (const nb of remaining) {
469	            if (preFreeSlots.length > 0) {
470	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位 → 立即進場
471	            } else {
472	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
473	            }
474	        }
475	
476	        // 不足的進場等所有退場完成後，使用騰出的 item 版位
477	        if (deferredEnter.length > 0) {
478	            Promise.all(outPromises).then(() => {
479	                for (const nb of deferredEnter) {
480	                    const idx = vacatingSlots.shift();
481	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
482	                    this.EnterAt(idx, nb);
483	                }
484	            });
485	        }
486	    }
487	
488	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
489	    private EnterAt(index: number, data: IBountyData) {
490	        const item = this.m_wantedPosterItems[index];
491	        if (!item) return;
492	        // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
493	        item.node.active = true;
494	        item.SetWantedPosterData(data);
495	        item.PlayIn();
496	        this.m_currentBounty[index] = data;
497	    }
498	
499	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
500	    private EnsureCurrentBountySize() {
501	        const count = this.m_wantedPosterItems.length;
502	        if (this.m_currentBounty.length === count) return;
503	        const next: (IBountyData | null)[] = new Array(count).fill(null);
504	        const keep = Math.min(this.m_currentBounty.length, count);
505	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
506	        this.m_currentBounty = next;
507	    }
508	
509	    /**
510	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
511	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
512	     */
513	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
514	        if (baseSymbol === null || baseSymbol === undefined) return [];
515	        const result: WantedPosterItem[] = [];
516	        for (const item of this.m_wantedPosterItems) {
517	            if (item && item.node.active && item.GetBaseSymbol() === baseSymbol) {
518	                result.push(item);
519	            }
520	        }
521	        return result;
522	    }
523	    /**
524	     * @ch 設置懸賞令 UI 顯示狀態
525	     * @param isShow 是否顯示
526	     */
527	    private SetWantedPosterUIShow(isShow: boolean) {
528	        if (!this.m_rootNode) {
529	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
530	            return;
531	        }
532	        this.m_rootNode.active = isShow;
533	    }
534	    //#endregion Methods
535	
536	    //#region 測試功能
537	    /**
538	     * @ch 測試按鍵處理
539	     * - 數字鍵 1：顯示 1 個懸賞令
540	     * - 數字鍵 2：顯示 2 個懸賞令
541	     * - 數字鍵 3：顯示 UI
542	     * - 數字鍵 4：隱藏 UI
543	     */
544	    private CheckTestKeyCode(event: EventKeyboard): void {
545	        if (!DEBUG) return;
546	        switch (event.keyCode) {
547	            case KeyCode.DIGIT_1:
548	                // 測試：顯示 1 個懸賞令
549	                this.SetWantedPosterData([
550	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
551	                ], true);
552	                break;
553	
554	            case KeyCode.DIGIT_2:
555	                // 測試：顯示 2 個懸賞令
556	                this.SetWantedPosterData([
557	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
558	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
559	                ], true);
560	                break;
561	
562	            case KeyCode.DIGIT_3:
563	                // 測試：顯示 UI
564	                this.SetWantedPosterUIShow(true);
565	                break;
566	
567	            case KeyCode.DIGIT_4:
568	                // 測試：隱藏 UI
569	                this.SetWantedPosterUIShow(false);
570	                break;
571	        }
572	    }
573	    //#endregion 測試功能
574	}
575	
