1	import { _decorator, Component, Label, Node, sp, tween, Tween, UIOpacity, warn } from 'cc';
2	import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
3	import Game_Define, { IBountyData, Symbol } from '../Game_Define';
4	const { ccclass, property } = _decorator;
5	
6	/**@ch 懸賞單 Spine 動畫名稱（常駐用 In/Out/Mark/Mark_Idle/Mark_Active，場上實例用 Symbol_In/Symbol_Active）*/
7	const ANIM = {
8	    IN: 'In',
9	    OUT: 'Out',
10	    MARK: 'Mark',
11	    MARK_IDLE: 'Mark_Idle',
12	    MARK_ACTIVE: 'Mark_Active',
13	    SYMBOL_IN: 'Symbol_In',
14	    SYMBOL_ACTIVE: 'Symbol_Active',
15	} as const;
16	
17	/**
18	 * @ch 依 Symbol 取對應 skin 名稱（M1~M9）
19	 * 利用 enum 反查（Symbol[Symbol.M1] === 'M1'），skin 名與 enum 名一致
20	 * @returns 'M1'~'M9'；超出範圍回 null
21	 */
22	function GetSkinNameBySymbol( symbolId: Symbol ): string | null {
23	    if ( symbolId < Symbol.M1 || symbolId > Symbol.M9 ) return null;
24	    return Symbol[ symbolId ] ?? null;
25	}
26	
27	/**
28	 * @ch 常駐懸賞單元件 — 播放 In / Out / Mark / Mark_Active 動畫
29	 * 倍率數字節點掛在 prefab 階層內，由 NewBoneFollow + NewSlotColorFollow 元件
30	 * 自動跟隨 spine 的 Wanted_NUM bone / slot（純編輯器設定，本元件不處理）
31	 */
32	@ccclass('WantedPosterItem')
33	export class WantedPosterItem extends Component {
34	    //#region Properties
35	    @property({
36	        type: sp.Skeleton,
37	        tooltip: '懸賞單 Spine（含 Wanted.skel）'
38	    })
39	    private m_spine: sp.Skeleton = null;
40	
41	    @property({
42	        type: Label,
43	        tooltip: '懸賞倍率（位置由 NewBoneFollow 跟隨 Wanted_NUM bone）'
44	    })
45	    private m_multiplierLabel: Label = null;
46	
47	    @property({
48	        type: UIOpacity,
49	        tooltip: '懸賞倍率透明度'
50	    })
51	    private m_multiplierLabelUIOpacity: UIOpacity = null;
52	
53	    @property({
54	        type: Node,
55	        tooltip: '懸賞倍率X9999 節點'
56	    })
57	    private m_x9999Node: Node = null;
58	    //#endregion Properties
59	
60	    //#region Variables
61	    /**@ch 當前綁定的 BaseSymbol*/
62	    private m_baseSymbol: Symbol = Symbol.MAX;
63	
64	    /**@ch 倍率 label 淡出時長（秒）*/
65	    private static readonly MULTIPLIER_FADE_OUT_DURATION: number = 0.1;
66	    //#endregion Variables
67	
68	    //#region Public API
69	    /**
70	     * @ch 設置懸賞單資料：切 skin、設數字、紀錄 BaseSymbol（不負責動畫觸發，由 Manager 決定）
71	     * @param data 懸賞單資料
72	     */
73	    public SetWantedPosterData( data: IBountyData ): void {
74	        this.m_baseSymbol = data.BaseSymbol as Symbol;
75	        this.SetSkinBySymbol( this.m_baseSymbol );
76	        this.SetMultiplierLabel( data.Multiple );
77	    }
78	
79	    /**@ch 取得當前綁定的 BaseSymbol（State 比對用）*/
80	    public GetBaseSymbol(): Symbol {
81	        return this.m_baseSymbol;
82	    }
83	
84	    /**@ch 播 In 動畫，等播完（重設倍率 opacity 為 255，開啟新展示週期）*/
85	    public PlayIn(): Promise<void> {
86	        this.ResetMultiplierOpacity();
87	        return this.PlayAnim( ANIM.IN, false );
88	    }
89	
90	    /**@ch 播 Out 動畫，等播完*/
91	    public PlayOut(): Promise<void> {
92	        return this.PlayAnim( ANIM.OUT, false );
93	    }
94	
95	    /**
96	     * @ch 直接顯示 In 動畫「已定位」的最後一幀靜止畫面（不播進場過程）
97	     * 用於 GAME_INTRO_COMPLETE：介紹已演完進場，這裡只要呈現定位完成的結果。
98	     * 取樣尾幀使 bone 落到 In 終點，倍率數字（NewBoneFollow 跟 Wanted_NUM bone）才會正確對位。
99	     * EH-1：m_spine 為 null → warn + 略過
100	     */
101	    public ShowInSettled(): void {
102	        this.ResetMultiplierOpacity();
103	        if ( !this.m_spine ) {
104	            warn( '[WantedPosterItem] ShowInSettled: m_spine 未設置' );
105	            return;
106	        }
107	        const entry = this.m_spine.setAnimation( 0, ANIM.IN, false );
108	        if ( entry ) entry.trackTime = entry.animationEnd;  // 跳到 In 最後一幀
109	        this.m_spine.updateAnimation( 0 );                  // 立即取樣套用該幀姿勢（當幀定位、不閃）
110	    }
111	
112	    /**
113	     * @ch 播 Mark，等 Mark 完成；完成後自動接 Mark_Idle loop（不等待 loop）
114	     * @returns Mark 動畫完成的 Promise（不含 Mark_Idle loop）
115	     */
116	    public async PlayMark(): Promise<void> {
117	        await this.PlayAnim( ANIM.MARK, false );
118	        // EH-1：若 spine 為 null，PlayAnim 已 warn 並 resolve；此處不再 addAnimation
119	        if ( !this.m_spine ) return;
120	        // 接 Mark_Idle loop 在 track 0（會被後續 PlayMarkActive 的 setAnimation 自動取代）
121	        this.m_spine.addAnimation( 0, ANIM.MARK_IDLE, true, 0 );
122	    }
123	
124	    /**@ch 播 Mark_Active（會打斷 Mark_Idle loop；同步淡出倍率 label）*/
125	    public PlayMarkActive(): Promise<void> {
126	        this.FadeOutMultiplierOpacity();
127	        return this.PlayAnim( ANIM.MARK_ACTIVE, false );
128	    }
129	
130	    /**@ch 播 Symbol_In，等播完（loop=false → stay at last frame；重設倍率 opacity 為 255）— 場上實例用 */
131	    public PlaySymbolIn(): Promise<void> {
132	        this.ResetMultiplierOpacity();
133	        return this.PlayAnim( ANIM.SYMBOL_IN, false );
134	    }
135	
136	    /**@ch 播 Symbol_Active，等播完（同步淡出倍率 label）— 場上實例用 */
137	    public PlaySymbolActive(): Promise<void> {
138	        this.FadeOutMultiplierOpacity();
139	        return this.PlayAnim( ANIM.SYMBOL_ACTIVE, false );
140	    }
141	
142	    /**
143	     * @ch 公開 skin 切換 API（場上實例用，不走 SetWantedPosterData 因為不需要設 multiplier label）
144	     * EH-2：Symbol 不在 M1~M9 範圍 → warn + 不切
145	     */
146	    public SetSkin( symbolId: Symbol ): void {
147	        this.m_baseSymbol = symbolId;
148	        this.SetSkinBySymbol( symbolId );
149	    }
150	
151	    /**
152	     * @ch 場上實例設定倍率顯示（合併組連乘值，純表演）；須在 SetSkin 之後呼叫
153	     * IF-2：委派既有 private SetMultiplierLabel，避免格式字串重複；label 為 null 時靜默（EH-3）
154	     */
155	    public SetFieldMultiplier( multiplier: number ): void {
156	        this.SetMultiplierLabel( multiplier );
157	    }
158	    //#endregion Public API
159	
160	    //#region Private
161	    /**
162	     * @ch 依 Symbol 切 skin（M1~M9）
163	     * EH-2：Symbol 不在範圍 → warn + 不切
164	     */
165	    private SetSkinBySymbol( symbolId: Symbol ): void {
166	        if ( !this.m_spine ) {
167	            warn( '[WantedPosterItem] SetSkinBySymbol: m_spine 未設置' );
168	            return;
169	        }
170	        const skinName = GetSkinNameBySymbol( symbolId );
171	        if ( !skinName ) {
172	            warn( '[WantedPosterItem] SetSkinBySymbol: Symbol 不在 M1~M9 範圍', symbolId );
173	            return;
174	        }
175	        this.m_spine.setSkin( skinName );
176	        this.m_spine.setSlotsToSetupPose();
177	    }
178	
179	    /**
180	     * @ch 設置倍率顯示（涵蓋常駐 item 與場上 spine 兩條顯示路徑）
181	     * 倍率 >= Game_Define.Multiplier_Max → 只顯示 m_x9999Node、隱藏倍率 Label
182	     * 反之 → 只顯示倍率 Label（*N）、隱藏 m_x9999Node
183	     */
184	    private SetMultiplierLabel( multiplier: number ): void {
185	        const isMax = multiplier >= Game_Define.Multiplier_Max;
186	        if ( this.m_x9999Node ) this.m_x9999Node.active = isMax;
187	        if ( this.m_multiplierLabel ) {
188	            this.m_multiplierLabel.node.active = !isMax;
189	            if ( !isMax ) this.m_multiplierLabel.string = `*${multiplier}`;
190	        }
191	    }
192	
193	    /**
194	     * @ch 倍率 label 淡出至 0（0.1s tween；Mark_Active / Symbol_Active 期間呼叫）
195	     * 連續觸發以 Tween.stopAllByTarget 防疊加；m_multiplierLabelUIOpacity 為 null 時靜默
196	     */
197	    private FadeOutMultiplierOpacity(): void {
198	        if ( !this.m_multiplierLabelUIOpacity ) return;
199	        Tween.stopAllByTarget( this.m_multiplierLabelUIOpacity );
200	        tween( this.m_multiplierLabelUIOpacity )
201	            .to( WantedPosterItem.MULTIPLIER_FADE_OUT_DURATION, { opacity: 0 } )
202	            .start();
203	    }
204	
205	    /**
206	     * @ch 倍率 label opacity 重設為 255（PlayIn / PlaySymbolIn 起手呼叫，開啟新展示週期）
207	     * 連續觸發以 Tween.stopAllByTarget 中斷殘留 tween；m_multiplierLabelUIOpacity 為 null 時靜默
208	     */
209	    private ResetMultiplierOpacity(): void {
210	        if ( !this.m_multiplierLabelUIOpacity ) return;
211	        Tween.stopAllByTarget( this.m_multiplierLabelUIOpacity );
212	        this.m_multiplierLabelUIOpacity.opacity = 255;
213	    }
214	
215	    /**
216	     * @ch 統一 spine 動畫播放封裝
