370	        {
371	            let bone = this.m_spineSkeleton.findBone( this.m_boneName );
372	            if ( bone )
373	            {
374	                let angleFactor = 0;
375	                let scaleXFactor = 1;
376	                let scaleYFactor = 1;
377	
378	                // 檢查是否已經 cache 過資料
379	                if ( !this.m_cacheAncestors || !this._isCached )
380	                {
