382	                    let spineAngle = 0;
383	                    let selfAngle = 0;
384	
385	                    let spineScaleX = 1;
386	                    let spineScaleY = 1;
387	                    let selfScaleX = 1;
388	                    let selfScaleY = 1;
389	
390	                    // 同步目標對象的旋轉及縮放資料
391	                    let parent = this.m_spineSkeleton.node;
392	                    while ( parent )
393	                    {
394	                        spineScaleX *= parent.scale.x;
395	                        spineScaleY *= parent.scale.y;
396	                        if ( parent.angle ) spineAngle += parent.angle; //有可能parent.angle NAN
397	                        //console.log("同步目標對象的旋轉及縮放資料","spineScale:X/Y/angle",spineScaleX,spineScaleY,spineAngle,"parent.scale:X/Y/angle",parent.scale.x,parent.scale.y,parent.angle)
398	                        parent = parent.parent;
399	                    }
400	
401	                    // 自己的旋轉及縮放資料
402	                    parent = this.node.parent;
403	                    while ( parent )
404	                    {
405	                        selfScaleX *= parent.scale.x;
406	                        selfScaleY *= parent.scale.y;
407	                        if ( parent.angle ) selfAngle -= parent.angle; //有可能parent.angle NAN
408	                        //console.log("自己的旋轉及縮放資料","spineScale:X/Y/angle",spineScaleX,spineScaleY,spineAngle,"parent.scale:X/Y/angle",parent.scale.x,parent.scale.y,parent.angle)
409	                        parent = parent.parent;
410	                    }
