import { _decorator, Enum, Component, Vec2, v2, isValid, v3, sp, CCClass, UITransform, Director, director } from "cc";
import { EDITOR, JSB } from "cc/env";
const { ccclass, property, executeInEditMode } = _decorator;

enum BoneName
{
    default = 1
}
const CCBoneName = Enum( {} );
const hash = function ( str: string )
{
    let hash = 0, i, chr;
    if ( str.length === 0 ) return hash;
    for ( i = 0; i < str.length; i++ )
    {
        chr = str.charCodeAt( i );
        hash = ( ( hash << 5 ) - hash ) + chr;
        hash |= 0;
    }
    return hash;
};

const PI = 3.1415927;
const degRad = PI / 180;
const radDeg = 180 / PI;

function cosDeg( degrees )
{
    return Math.cos( degrees * degRad );
}

function sinDeg( degrees )
{
    return Math.sin( degrees * degRad );
}

function localToWorldRotation( a, b, c, d, localRotation )
{
    let sin = sinDeg( localRotation ), cos = cosDeg( localRotation );
    return Math.atan2( cos * c + sin * d, cos * a + sin * b ) * radDeg;
}

