        if ( bValite == false ) console.log( "[spBoneFollow] 輸入的骨頭", value, "並不存在！請檢查名稱是否正確！" );
        else console.log( "[spBoneFollow] 輸入的骨頭", value, "已找到！" );
    }
    @property( {
        type: CCBoneName,
        visible: false,
    } )
    __boneIndex: BoneName = BoneName.default;

    @property( {
        type: CCBoneName,
        visible: true,
        displayName: "SelectFromList",
        tooltip: "可從此下拉選單選擇骨頭"
    } )
    get _boneIndex(): BoneName
    {
        return this.__boneIndex;
    }
    set _boneIndex( value: BoneName )
    {
        this.__boneIndex = value;
        this._BoneEnumList.forEach( type =>
        {
            if ( type.value == value ) this.m_boneName = type.name;
        } );
        this.__boneIndex = 0;
        console.log( "set __boneIndex ", value, "m_boneName:", this.m_boneName )
    }
    @property( {
        displayName: "Cache Ancestors",
        tooltip: "是否快取旋轉及縮放的上層資料，預設開啟。如果父層以上會有動態調整旋轉及縮放則需取消勾選此選項，或是維持啟用狀態但於需要的時刻呼叫 CacheUpdate 方法"

    } )
    m_cacheAncestors: boolean = true;
    @property( {
        displayName: "Position",
        tooltip: "是否同步位置"
    } )
    m_followPosition: boolean = false;
    @property( {
        displayName: "Position Offset",
        tooltip: "額外本體位置偏移",
        visible: function ()
        {
            return this.m_followPosition;
        }
    } )
    m_positionOffset = v2( 0, 0 );
    @property( {
        displayName: "Rotation",
        tooltip: "是否同步旋轉"
    } )
    m_followRotation: boolean = false;
    @property( {
        displayName: "Rotation Localization",
        tooltip: "是否將目標旋轉角度轉換成區域旋轉角度",
        visible: function ()
        {
            return this.m_followRotation;
        }
    } )
    m_rotationLocalization: boolean = true;
    @property( {
        displayName: "Rotation Factor",
        tooltip: "額外本體旋轉",
        visible: function ()
        {
            return this.m_followRotation;
        }
    } )
    m_rotationFactor: number = 0;
    @property( {
        displayName: "Scale",
        tooltip: "是否同步縮放"
    } )
    m_followScale: boolean = false;
    @property( {
        displayName: "Scale Localization",
        tooltip: "是否將目標縮放量轉換成區域縮放量",
        visible: function ()
        {
            return this.m_followScale;
        }
    } )
    m_scaleLocalization: boolean = true;
    @property( {
        displayName: "Scale Factor",
        tooltip: "額外本體大小縮放",
        visible: function ()
        {
            return this.m_followScale;
        }
    } )
    m_scaleFactor: Vec2 = v2( 1, 1 );

    private m_isFirstActive: boolean = true;

    __preload()
    {
    }

    onLoad()
    {
        if ( EDITOR && !this.m_preview ) return;
        this._oldAngle = this.node.angle;
        this._oldScaleX = this.node.scale.x;
        this._oldScaleY = this.node.scale.y;
    }

    start()
    {
        if ( EDITOR && this.m_spineSkeleton )
        {
            //console.log("spBoneFollow __preload",this.m_spineSkeleton)
            this._refreshInspector();
        }
    }

    onEnable()
    {
        director.on( Director.EVENT_BEFORE_DRAW, this.BoneSync, this );
    }

    onDisable()
    {
        director.off( Director.EVENT_BEFORE_DRAW, this.BoneSync, this );
    }

    onDestroy()
    {
        this._oldAngle = null;
        this._oldScaleX = null;
        this._oldScaleY = null;
        this._isCached = null;
        this._cachedRotation = null;
        this._cachedScaleX = null;
        this._cachedScaleY = null;
        this.m_spineSkeleton = null;
        this.m_boneName = null;
        this.m_cacheAncestors = null;
        this.m_followPosition = null;
        this.m_followRotation = null;
        this.m_rotationLocalization = null;
        this.m_followScale = null;
        this.m_scaleLocalization = null;
    }

    /**
     * 骨骼參數同步
     */
    BoneSync()
    {
        if ( EDITOR && !this.m_preview ) return;

        // 第1次開啟節點骨架還沒被更新，強制更新一次，避免 Scale 為 0
        if ( this.m_isFirstActive && this.m_spineSkeleton && this.m_spineSkeleton._skeleton )
        {
            this.m_isFirstActive = false;
            this.m_spineSkeleton._skeleton.updateWorldTransform();
        }

        if ( this.m_spineSkeleton && this.m_boneName != "" && ( this.m_followPosition || this.m_followRotation || this.m_followScale ) )
        {
            let bone = this.m_spineSkeleton.findBone( this.m_boneName );
            if ( bone )
            {
                let angleFactor = 0;
                let scaleXFactor = 1;
                let scaleYFactor = 1;

                // 檢查是否已經 cache 過資料
                if ( !this.m_cacheAncestors || !this._isCached )
                {
                    // [還沒 cache 資料] => 計算旋轉及縮放資料
                    let spineAngle = 0;
                    let selfAngle = 0;

                    let spineScaleX = 1;
                    let spineScaleY = 1;
                    let selfScaleX = 1;
                    let selfScaleY = 1;

                    // 同步目標對象的旋轉及縮放資料
                    let parent = this.m_spineSkeleton.node;
                    while ( parent )
                    {
                        spineScaleX *= parent.scale.x;
                        spineScaleY *= parent.scale.y;
                        if ( parent.angle ) spineAngle += parent.angle; //有可能parent.angle NAN
                        //console.log("同步目標對象的旋轉及縮放資料","spineScale:X/Y/angle",spineScaleX,spineScaleY,spineAngle,"parent.scale:X/Y/angle",parent.scale.x,parent.scale.y,parent.angle)
                        parent = parent.parent;
                    }

                    // 自己的旋轉及縮放資料
                    parent = this.node.parent;
                    while ( parent )
                    {
                        selfScaleX *= parent.scale.x;
                        selfScaleY *= parent.scale.y;
                        if ( parent.angle ) selfAngle -= parent.angle; //有可能parent.angle NAN
                        //console.log("自己的旋轉及縮放資料","spineScale:X/Y/angle",spineScaleX,spineScaleY,spineAngle,"parent.scale:X/Y/angle",parent.scale.x,parent.scale.y,parent.angle)
                        parent = parent.parent;
                    }
                    // 計算轉換成自己的旋轉及縮放
                    this._cachedRotation = spineAngle + selfAngle;
                    this._cachedScaleX = spineScaleX / selfScaleX;
                    this._cachedScaleY = spineScaleY / selfScaleY;
                    //console.log("spineAngle",spineAngle,"selfAngle",selfAngle,"this._cachedRotation",this._cachedRotation);

                    // 標註 cache 完成
                    this._isCached = true;
                }

                // 取出旋轉及縮放資料
                angleFactor = this.m_rotationLocalization ? this._cachedRotation : this._oldAngle;
                scaleXFactor = this.m_scaleLocalization ? this._cachedScaleX : this._oldScaleX;
                scaleYFactor = this.m_scaleLocalization ? this._cachedScaleY : this._oldScaleY;
                //console.log("this.m_rotationLocalization", this.m_rotationLocalization,"_cachedRotation",this._cachedRotation,"this._oldAngle",this._oldAngle,"angleFactor",angleFactor);
                // 檢查是否啟用旋轉同步
                if ( this.m_followRotation )
                {
                    // [啟用旋轉同步]
                    let parentBone = bone.parent;
                    let arotation = JSB ? bone.appliedRotation : bone.arotation;
                    //console.log("this.node.getRotation", this.node.getRotation(),"angleFactor",angleFactor);
                    let Rotation = angleFactor + ( !isValid( parentBone ) ? bone.arotation : localToWorldRotation( parentBone.a, parentBone.b, parentBone.c, parentBone.d, arotation ) ) + this.m_rotationFactor;
                    this.node.setRotationFromEuler( v3( 0, 0, Rotation ) );
                    //console.log("this.node.angle after",Rotation,this.node.getRotation());
                }

                // 檢查是否啟用縮放同步
                if ( this.m_followScale )
                {
                    // [啟用縮放同步]
                    this.node.setScale( scaleXFactor * bone.getWorldScaleX() * this.m_scaleFactor.x, scaleYFactor * bone.getWorldScaleY() * this.m_scaleFactor.y );
                }

                // 檢查是否啟用位置同步
                if ( this.m_followPosition )
                {
                    // [啟用位置同步]
                    let worldPos = this.m_spineSkeleton.node.getComponent( UITransform ).convertToWorldSpaceAR( v3( bone.worldX + this.m_positionOffset.x, bone.worldY + this.m_positionOffset.y, 0 ) );
                    let localPos = this.node.parent.getComponent( UITransform ).convertToNodeSpaceAR( worldPos );
                    this.node.setPosition( v3( localPos.x, localPos.y ) );
                }
            }
        }
    }

    /**
     * 刷新編輯器屬性面板
     */
    _refreshInspector()
    {
        if ( !EDITOR ) return;
        this._updateBoneEnum();
        //Editor.Utils.refreshSelectedInspector("node", this.node.uuid);
    }

    /**
     * 更新面板骨骼列舉屬性欄位
     */
    _updateBoneEnum()
    {
        if ( !EDITOR ) return;
        this._BoneEnumList = [];

        if ( this.m_spineSkeleton )
        {
            let bones = this.m_spineSkeleton._skeleton.bones;
            for ( let i = bones.length - 1; i >= 0; i-- )
            {
                let eachBone = bones[ i ];
                let name = eachBone.data.name;
                this._BoneEnumList.push( { name: name, value: hash( name ) } );//使用hash儲存以避免因為spine skin順序異動而對應錯誤
            }
            this._BoneEnumList.sort( ( a, b ) =>
            {
                if ( a.name < b.name ) return -1;
                else if ( a.name > b.name ) return 1;
                else return 0;
            } );

            CCClass.Attr.setClassAttr( this, "_boneIndex", "type", "Enum" );
            CCClass.Attr.setClassAttr( this, "_boneIndex", "enumList", this._BoneEnumList );

            //console.log("enumList ", this._BoneEnumList)
            //console.log("_boneIndex ", this._boneIndex,"m_boneName",this.m_boneName)
        }
    }
}

