import { _decorator, Component, Label, Node, sp, tween, Tween, UIOpacity, warn } from 'cc';
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import Game_Define, { IBountyData, Symbol } from '../Game_Define';
const { ccclass, property } = _decorator;

/**@ch 懸賞單 Spine 動畫名稱（常駐用 In/Out/Mark/Mark_Idle/Mark_Active，場上實例用 Symbol_In/Symbol_Active）*/
const ANIM = {
    IN: 'In',
    OUT: 'Out',
    MARK: 'Mark',
    MARK_IDLE: 'Mark_Idle',
    MARK_ACTIVE: 'Mark_Active',
    SYMBOL_IN: 'Symbol_In',
    SYMBOL_ACTIVE: 'Symbol_Active',
} as const;

/**
 * @ch 依 Symbol 取對應 skin 名稱（M1~M9）
 * 利用 enum 反查（Symbol[Symbol.M1] === 'M1'），skin 名與 enum 名一致
 * @returns 'M1'~'M9'；超出範圍回 null
 */
function GetSkinNameBySymbol( symbolId: Symbol ): string | null {
    if ( symbolId < Symbol.M1 || symbolId > Symbol.M9 ) return null;
    return Symbol[ symbolId ] ?? null;
}

/**
 * @ch 常駐懸賞單元件 — 播放 In / Out / Mark / Mark_Active 動畫
 * 倍率數字節點掛在 prefab 階層內，由 NewBoneFollow + NewSlotColorFollow 元件
 * 自動跟隨 spine 的 Wanted_NUM bone / slot（純編輯器設定，本元件不處理）
 */
@ccclass('WantedPosterItem')
export class WantedPosterItem extends Component {
    //#region Properties
    @property({
        type: sp.Skeleton,
        tooltip: '懸賞單 Spine（含 Wanted.skel）'
    })
    private m_spine: sp.Skeleton = null;

    @property({
        type: Label,
        tooltip: '懸賞倍率（位置由 NewBoneFollow 跟隨 Wanted_NUM bone）'
    })
    private m_multiplierLabel: Label = null;

    @property({
        type: UIOpacity,
        tooltip: '懸賞倍率透明度'
    })
    private m_multiplierLabelUIOpacity: UIOpacity = null;

    @property({
        type: Node,
        tooltip: '懸賞倍率X9999 節點'
    })
    private m_x9999Node: Node = null;

    @property({
        type: Node,
        tooltip: '內容容器（Spine + 倍率）。ghost 佔位時關閉此節點：內容隱形但 item root 仍被 cc.Layout 計入版位'
    })
    private m_contentNode: Node = null;
    //#endregion Properties

    //#region Variables
    /**@ch 當前綁定的 BaseSymbol*/
    private m_baseSymbol: Symbol = Symbol.MAX;

    /**@ch 倍率 label 淡出時長（秒）*/
    private static readonly MULTIPLIER_FADE_OUT_DURATION: number = 0.1;
    //#endregion Variables

    //#region Public API
    /**
     * @ch 設置懸賞單資料：切 skin、設數字、紀錄 BaseSymbol（不負責動畫觸發，由 Manager 決定）
     * @param data 懸賞單資料
     */
    public SetWantedPosterData( data: IBountyData ): void {
        this.m_baseSymbol = data.BaseSymbol as Symbol;
        this.SetSkinBySymbol( this.m_baseSymbol );
        this.SetMultiplierLabel( data.Multiple );
    }

    /**@ch 取得當前綁定的 BaseSymbol（State 比對用）*/
    public GetBaseSymbol(): Symbol {
        return this.m_baseSymbol;
    }

    /**@ch 播 In 動畫，等播完（重設倍率 opacity 為 255，開啟新展示週期）*/
    public PlayIn(): Promise<void> {
        this.ResetMultiplierOpacity();
        return this.PlayAnim( ANIM.IN, false );
    }

    /**@ch 播 Out 動畫，等播完*/
    public PlayOut(): Promise<void> {
        return this.PlayAnim( ANIM.OUT, false );
    }

    /**
     * @ch 直接顯示 In 動畫「已定位」的最後一幀靜止畫面（不播進場過程）
     * 用於 GAME_INTRO_COMPLETE：介紹已演完進場，這裡只要呈現定位完成的結果。
     * 取樣尾幀使 bone 落到 In 終點，倍率數字（NewBoneFollow 跟 Wanted_NUM bone）才會正確對位。
     * EH-1：m_spine 為 null → warn + 略過
     */
    public ShowInSettled(): void {
        this.ResetMultiplierOpacity();
        if ( !this.m_spine ) {
            warn( '[WantedPosterItem] ShowInSettled: m_spine 未設置' );
            return;
        }
        const entry = this.m_spine.setAnimation( 0, ANIM.IN, false );
        if ( entry ) entry.trackTime = entry.animationEnd;  // 跳到 In 最後一幀
        this.m_spine.updateAnimation( 0 );                  // 立即取樣套用該幀姿勢（當幀定位、不閃）
    }

    /**
     * @ch 播 Mark，等 Mark 完成；完成後自動接 Mark_Idle loop（不等待 loop）
     * @returns Mark 動畫完成的 Promise（不含 Mark_Idle loop）
     */
    public async PlayMark(): Promise<void> {
        await this.PlayAnim( ANIM.MARK, false );
        // EH-1：若 spine 為 null，PlayAnim 已 warn 並 resolve；此處不再 addAnimation
        if ( !this.m_spine ) return;
        // 接 Mark_Idle loop 在 track 0（會被後續 PlayMarkActive 的 setAnimation 自動取代）
        this.m_spine.addAnimation( 0, ANIM.MARK_IDLE, true, 0 );
    }

    /**@ch 播 Mark_Active（會打斷 Mark_Idle loop；同步淡出倍率 label）*/
    public PlayMarkActive(): Promise<void> {
        this.FadeOutMultiplierOpacity();
        return this.PlayAnim( ANIM.MARK_ACTIVE, false );
    }

    /**@ch 播 Symbol_In，等播完（loop=false → stay at last frame；重設倍率 opacity 為 255）— 場上實例用 */
    public PlaySymbolIn(): Promise<void> {
        this.ResetMultiplierOpacity();
        return this.PlayAnim( ANIM.SYMBOL_IN, false );
    }

    /**@ch 播 Symbol_Active，等播完（同步淡出倍率 label）— 場上實例用 */
    public PlaySymbolActive(): Promise<void> {
        this.FadeOutMultiplierOpacity();
        return this.PlayAnim( ANIM.SYMBOL_ACTIVE, false );
    }

    /**
     * @ch 公開 skin 切換 API（場上實例用，不走 SetWantedPosterData 因為不需要設 multiplier label）
     * EH-2：Symbol 不在 M1~M9 範圍 → warn + 不切
     */
    public SetSkin( symbolId: Symbol ): void {
        this.m_baseSymbol = symbolId;
        this.SetSkinBySymbol( symbolId );
    }

    /**
     * @ch 場上實例設定倍率顯示（合併組連乘值，純表演）；須在 SetSkin 之後呼叫
     * IF-2：委派既有 private SetMultiplierLabel，避免格式字串重複；label 為 null 時靜默（EH-3）
     */
    public SetFieldMultiplier( multiplier: number ): void {
        this.SetMultiplierLabel( multiplier );
    }
    //#endregion Public API

    //#region Private
    /**
     * @ch 依 Symbol 切 skin（M1~M9）
     * EH-2：Symbol 不在範圍 → warn + 不切
     */
    private SetSkinBySymbol( symbolId: Symbol ): void {
        if ( !this.m_spine ) {
            warn( '[WantedPosterItem] SetSkinBySymbol: m_spine 未設置' );
            return;
        }
        const skinName = GetSkinNameBySymbol( symbolId );
        if ( !skinName ) {
            warn( '[WantedPosterItem] SetSkinBySymbol: Symbol 不在 M1~M9 範圍', symbolId );
            return;
        }
        this.m_spine.setSkin( skinName );
        this.m_spine.setSlotsToSetupPose();
    }

    /**
     * @ch 設置倍率顯示（涵蓋常駐 item 與場上 spine 兩條顯示路徑）
     * 倍率 >= Game_Define.Multiplier_Max → 只顯示 m_x9999Node、隱藏倍率 Label
     * 反之 → 只顯示倍率 Label（*N）、隱藏 m_x9999Node
     */
    private SetMultiplierLabel( multiplier: number ): void {
        const isMax = multiplier >= Game_Define.Multiplier_Max;
        if ( this.m_x9999Node ) this.m_x9999Node.active = isMax;
        if ( this.m_multiplierLabel ) {
            this.m_multiplierLabel.node.active = !isMax;
            if ( !isMax ) this.m_multiplierLabel.string = `*${multiplier}`;
        }
    }

    /**
     * @ch 倍率 label 淡出至 0（0.1s tween；Mark_Active / Symbol_Active 期間呼叫）
     * 連續觸發以 Tween.stopAllByTarget 防疊加；m_multiplierLabelUIOpacity 為 null 時靜默
     */
    private FadeOutMultiplierOpacity(): void {
        if ( !this.m_multiplierLabelUIOpacity ) return;
        Tween.stopAllByTarget( this.m_multiplierLabelUIOpacity );
        tween( this.m_multiplierLabelUIOpacity )
            .to( WantedPosterItem.MULTIPLIER_FADE_OUT_DURATION, { opacity: 0 } )
            .start();
    }

    /**
     * @ch 倍率 label opacity 重設為 255（PlayIn / PlaySymbolIn 起手呼叫，開啟新展示週期）
     * 連續觸發以 Tween.stopAllByTarget 中斷殘留 tween；m_multiplierLabelUIOpacity 為 null 時靜默
     */
    private ResetMultiplierOpacity(): void {
        if ( !this.m_multiplierLabelUIOpacity ) return;
        Tween.stopAllByTarget( this.m_multiplierLabelUIOpacity );
        this.m_multiplierLabelUIOpacity.opacity = 255;
    }

    /**
     * @ch 統一 spine 動畫播放封裝
     * EH-1：m_spine 為 null → warn + 立刻 resolve
     */
    private async PlayAnim( animName: string, loop: boolean ): Promise<void> {
        if ( !this.m_spine ) {
            warn( '[WantedPosterItem] PlayAnim: m_spine 未設置，跳過動畫', animName );
            return;
        }
        await SpineKit.PlayAnimation( this.m_spine, animName, loop, 0 );
    }
    //#endregion Private
}

